-- Step 2: Insert orphan communications linked to their new placeholder accounts
INSERT INTO public.communications (id, account_id, channel, occurred_at, summary, direction, metadata, created_at, updated_at)
SELECT 
  comm.id::uuid,
  acc.id as account_id,
  CASE 
    WHEN comm.channel = 'In person' THEN 'in_person'
    WHEN comm.channel = 'Site Visit' THEN 'site_visit'
    ELSE LOWER(REPLACE(comm.channel, ' ', '_'))
  END as channel,
  comm.occurred_at::timestamptz,
  comm.summary,
  'outbound' as direction,
  jsonb_build_object(
    'legacy_status', comm.status,
    'company_name', comm.company_name,
    'person_name', comm.person_name,
    'contact_info', comm.contact_info,
    'category', comm.category
  ) as metadata,
  comm.created_at::timestamptz,
  comm.updated_at::timestamptz
